(window.webpackJsonp=window.webpackJsonp||[]).push([[336],{605:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> kConcatenationMaxSum = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr, k</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> MOD=<span class=\\"hljs-number\\">1e9</span>+<span class=\\"hljs-number\\">7</span>\\n  <span class=\\"hljs-keyword\\">let</span> max=<span class=\\"hljs-built_in\\">Math</span>.max.apply(<span class=\\"hljs-built_in\\">Math</span>,arr)\\n  <span class=\\"hljs-keyword\\">if</span>(max&lt;=<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> sum=arr.reduce(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a+b)\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">if</span>(sum&gt;<span class=\\"hljs-number\\">0</span>){\\n    res=maxSubSum(arr)+sum*(k<span class=\\"hljs-number\\">-1</span>) % MOD\\n  }<span class=\\"hljs-keyword\\">else</span>{\\n    <span class=\\"hljs-keyword\\">let</span> mergeArr=arr\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;<span class=\\"hljs-built_in\\">Math</span>.min(k,<span class=\\"hljs-number\\">2</span>);i++){\\n      mergeArr=mergeArr.concat(arr)\\n    }\\n    res=maxSubSum(mergeArr) % MOD\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  \\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">maxSubSum</span>(<span class=\\"hljs-params\\">arr</span>)</span>{\\n    <span class=\\"hljs-comment\\">// console.log(arr)</span>\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> max=-<span class=\\"hljs-literal\\">Infinity</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;arr.length;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(res+arr[i]&lt;=<span class=\\"hljs-number\\">0</span>){\\n        res=<span class=\\"hljs-number\\">0</span>\\n      }<span class=\\"hljs-keyword\\">else</span>{\\n        res+=arr[i] \\n      }\\n      max=<span class=\\"hljs-built_in\\">Math</span>.max(max,res)\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> max\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"k-concatenation-maximum-sum","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4&nbsp;<code>arr</code>&nbsp;\u548c\u4e00\u4e2a\u6574\u6570&nbsp;<code>k</code>\u3002</p>\\n\\n<p>\u9996\u5148\uff0c\u6211\u4eec\u8981\u5bf9\u8be5\u6570\u7ec4\u8fdb\u884c\u4fee\u6539\uff0c\u5373\u628a\u539f\u6570\u7ec4 <code>arr</code> \u91cd\u590d&nbsp;<code>k</code>&nbsp;\u6b21\u3002</p>\\n\\n<blockquote>\\n<p>\u4e3e\u4e2a\u4f8b\u5b50\uff0c\u5982\u679c&nbsp;<code>arr&nbsp;= [1, 2]</code> \u4e14 <code>k = 3</code>\uff0c\u90a3\u4e48\u4fee\u6539\u540e\u7684\u6570\u7ec4\u5c31\u662f&nbsp;<code>[1, 2, 1, 2, 1, 2]</code>\u3002</p>\\n</blockquote>\\n\\n<p>\u7136\u540e\uff0c\u8bf7\u4f60\u8fd4\u56de\u4fee\u6539\u540e\u7684\u6570\u7ec4\u4e2d\u7684\u6700\u5927\u7684\u5b50\u6570\u7ec4\u4e4b\u548c\u3002</p>\\n\\n<p>\u6ce8\u610f\uff0c\u5b50\u6570\u7ec4\u957f\u5ea6\u53ef\u4ee5\u662f <code>0</code>\uff0c\u5728\u8fd9\u79cd\u60c5\u51b5\u4e0b\u5b83\u7684\u603b\u548c\u4e5f\u662f <code>0</code>\u3002</p>\\n\\n<p>\u7531\u4e8e&nbsp;<strong>\u7ed3\u679c\u53ef\u80fd\u4f1a\u5f88\u5927</strong>\uff0c\u6240\u4ee5\u9700\u8981 <strong>\u6a21\uff08mod\uff09</strong>&nbsp;<code>10^9 + 7</code>&nbsp;\u540e\u518d\u8fd4\u56de\u3002&nbsp;</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,2], k = 3\\n<strong>\u8f93\u51fa\uff1a</strong>9\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,-2,1], k = 5\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [-1,-2], k = 7\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= arr.length &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= k &lt;= 10^5</code></li>\\n\\t<li><code>-10^4 &lt;= arr[i] &lt;= 10^4</code></li>\\n</ul>\\n","title":"1191. K \u6b21\u4e32\u8054\u540e\u6700\u5927\u5b50\u6570\u7ec4\u4e4b\u548c","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1191"}')}}]);